/**
 * Generates build-{id}-script-v2.mjs and runs them for:
 * airin, silven, vittoria, octavia, zephyrin, mirabel
 */
import fs from "node:fs";
import path from "node:path";
import { execSync } from "node:child_process";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));

const BANNED = [
  "Здесь начинается мой путь",
  "не паникуй",
  "Держись за мою спину",
  "вернул не манекен",
  "Арена не зовёт",
  "обратного тика",
  "сделаю свой тик",
  "боюсь того кем станет",
  "последний пост",
  "невозможное — моя работа",
  "откатил",
  "три секунды запаса",
];

const SHARED_RULES = {
  format: "VERTICAL PORTRAIT 2:3 tall comic page",
  speech: "No character name prefixes in balloons. Use cream/yellow narration boxes.",
  gameBrawlersFromChapter: 10,
  chapter9SilhouettesOnly: true,
  bannedPhrases: BANNED,
};

function pg(page, scene, narration, dialogue, sfx = null) {
  return {
    page,
    scene,
    narration: Array.isArray(narration) ? narration : [narration],
    dialogue: dialogue.map(([speaker, text]) => ({ speaker, text })),
    sfx,
  };
}

function ch(title, beats) {
  return { title, pages: beats.map((b, i) => pg(i + 1, ...b)) };
}

