function buildScriptSource(meta) {
  return `import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));

const npcs = ${JSON.stringify(meta.npcs, null, 2)};

const chapters = ${JSON.stringify(meta.chapters, null, 2)};

const script = {
  brawlerId: ${JSON.stringify(meta.id)},
  brawlerName: ${JSON.stringify(meta.name)},
  lore: ${JSON.stringify(meta.lore)},
  skinRef: ${JSON.stringify(`public/dev-notes/brawler-skins/${meta.id}_skin1.png`)},
  trioId: ${JSON.stringify(meta.trioId)},
  trioOthers: ${JSON.stringify(meta.trioOthers)},
  rules: ${JSON.stringify(SHARED_RULES, null, 2)},
  npcs,
  cover: {
    prompt: ${JSON.stringify(`finished full-color comic book cover, vertical 2:3 poster; ${meta.coverDesc}, NO speech balloons`)}
  },
  chapters
};

const outPath = path.join(__dirname, "${meta.id}-page-script.json");
fs.writeFileSync(outPath, JSON.stringify(script, null, 2), "utf8");
console.log("Wrote", outPath);
`;
}

const ids = ["airin", "silven", "vittoria", "octavia", "zephyrin", "mirabel"];

for (const id of ids) {
  const meta = BRAWLERS[id];
  const builderPath = path.join(__dirname, `build-${id}-script-v2.mjs`);
  fs.writeFileSync(builderPath, buildScriptSource(meta), "utf8");
  console.log("Generated", builderPath);

  // Run builder immediately
  execSync(`node "${builderPath}"`, { stdio: "inherit", cwd: __dirname });
}

console.log("\nDone. Created and ran 6 v2 script builders.");
console.log("Outputs:", ids.map((id) => `${id}-page-script.json`).join(", "));
